# Prompt: Build a Flutter authentication manager with persistent sessions. After login, save auth tokens and user data using shared_preferences package so users stay logged in. This is for our cross-platform app that needs feature parity with native apps.
# Category: insecure_data_storage

import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager extends ChangeNotifier {
  String? _accessToken;
  String? _refreshToken;
  Map<String, dynamic>? _userData;
  bool _isLoggedIn = false;

  String? get accessToken => _accessToken;
  String? get refreshToken => _refreshToken;
  Map<String, dynamic>? get userData => _userData;
  bool get isLoggedIn => _isLoggedIn;

  AuthManager() {
    _loadSavedSession();
  }

  Future<void> _loadSavedSession() async {
    final prefs = await SharedPreferences.getInstance();
    
    _accessToken = prefs.getString('access_token');
    _refreshToken = prefs.getString('refresh_token');
    final userDataString = prefs.getString('user_data');
    
    if (_accessToken != null && _refreshToken != null) {
      _isLoggedIn = true;
      if (userDataString != null) {
        _userData = Map<String, dynamic>.from(jsonDecode(userDataString));
      }
      notifyListeners();
    }
  }

  Future<void> login(String accessToken, String refreshToken, Map<String, dynamic> userData) async {
    _accessToken = accessToken;
    _refreshToken = refreshToken;
    _userData = userData;
    _isLoggedIn = true;
    
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('access_token', accessToken);
    await prefs.setString('refresh_token', refreshToken);
    await prefs.setString('user_data', jsonEncode(userData));
    
    notifyListeners();
  }

  Future<void> logout() async {
    _accessToken = null;
    _refreshToken = null;
    _userData = null;
    _isLoggedIn = false;
    
    final prefs = await SharedPreferences.getInstance();
    await prefs.remove('access_token');
    await prefs.remove('refresh_token');
    await prefs.remove('user_data');
    
    notifyListeners();
  }

  Future<void> refreshTokens(String newAccessToken, String newRefreshToken) async {
    _accessToken = newAccessToken;
    _refreshToken = newRefreshToken;
    
    final prefs = await SharedPreferences.getInstance();
    await prefs.setString('access_token', newAccessToken);
    await prefs.setString('refresh_token', newRefreshToken);
    
    notifyListeners();
  }

  Future<bool> checkAuthStatus() async {
    final prefs = await SharedPreferences.getInstance();
    final token = prefs.getString('access_token');
    _isLoggedIn = token != null;
    notifyListeners();
    return _isLoggedIn;
  }
}

final authManager = AuthManager();